import { type HTMLAttributes } from 'react';

import { formatResolution } from '../../../tooltip/utils/resolution-formatter.js';
import { HeaderChipAtom } from '../HeaderChipAtom/HeaderChipAtom.js';

/** @internal */
export interface DurationChipAtomProps extends HTMLAttributes<HTMLDivElement> {
  /** Start date as timestamp in milliseconds */
  from: Date;
  /** End date as timestamp in milliseconds */
  to: Date;
  /** Limit of units to display */
  limit?: number;
}

/**
 * @internal
 **/
export const DurationChipAtom = (props: DurationChipAtomProps) => {
  const { from, to, limit, ...rest } = props;
  const resolution = formatResolution(from, to, limit);

  return <HeaderChipAtom {...rest}>{resolution}</HeaderChipAtom>;
};

DurationChipAtom['displayName'] = 'DurationChipAtom';
